# Import necessary libraries
import time
from machine import Pin
from dht import DHT11
from umqtt.simple import MQTTClient

# Set up DHT11 sensor
dht_sensor = DHT11(Pin(4))

# Set up MQTT connection
client_id = 'esp32_sensor'
broker_ip = '192.168.1.100'  # Replace with your MQTT broker IP address
client = MQTTClient(client_id, broker_ip)

def connect_and_publish():
    client.connect()
    while True:
        dht_sensor.measure()
        temp = dht_sensor.temperature()
        client.publish('sensors/temp', str(temp))
        time.sleep(10)

# Connect and publish sensor data
connect_and_publish()